import{_ as e,c as a,o as r,a8 as n}from"./chunks/framework.DMZhn_gK.js";const p=JSON.parse('{"title":"压力测试","description":"压力测试","frontmatter":{"title":"压力测试","tags":["Java， 压力测试"],"categories":["Java"],"date":"2026-4-6","description":"压力测试","articleGPT":"压力测试","references":[{"title":"Java","url":"https://github.com/imsyy/vitepress-theme-curve"}]},"headers":[],"relativePath":"java/压力测试.md","filePath":"java/压力测试.md","lastUpdated":1776154279000}'),s={name:"java/压力测试.md"};function l(i,t,o,d,g,c){return r(),a("div",null,[...t[0]||(t[0]=[n('<h2 id="压力测试" tabindex="-1">压力测试 <a class="header-anchor" href="#压力测试" aria-label="Permalink to &quot;压力测试&quot;">​</a></h2><h3 id="_1-响应时间-response-time-rt" tabindex="-1">1. 响应时间（Response Time, RT） <a class="header-anchor" href="#_1-响应时间-response-time-rt" aria-label="Permalink to &quot;1. 响应时间（Response Time, RT）&quot;">​</a></h3><p><strong>定义</strong>：用户从客户端发起一个请求开始，到客户端接收到服务器端返回的响应结束，整个过程所耗费的总时间。</p><p><strong>核心意义</strong>：直接反映用户体验，是衡量系统 “快慢” 最直观的指标，<strong>数值越小，用户体验越好</strong>。</p><hr><h3 id="_2-吞吐量类核心指标-hps-tps-qps" tabindex="-1">2. 吞吐量类核心指标（HPS / TPS / QPS） <a class="header-anchor" href="#_2-吞吐量类核心指标-hps-tps-qps" aria-label="Permalink to &quot;2. 吞吐量类核心指标（HPS / TPS / QPS）&quot;">​</a></h3><p>这三个指标都是衡量系统<strong>每秒处理能力</strong>的核心吞吐量指标，<strong>数值越大，系统处理能力越强</strong>，三者的区别和适用场景如下：</p><table tabindex="0"><thead><tr><th style="text-align:center;">指标</th><th style="text-align:center;">全称</th><th style="text-align:center;">定义</th><th style="text-align:center;">适用场景</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>HPS</strong></td><td style="text-align:center;">Hits Per Second</td><td style="text-align:center;">每秒点击次数，单位：次 / 秒</td><td style="text-align:center;">衡量对服务器的单击请求数，多用于前端 / 页面访问场景</td></tr><tr><td style="text-align:center;"><strong>TPS</strong></td><td style="text-align:center;">Transaction per Second</td><td style="text-align:center;">系统每秒处理交易数，单位：笔 / 秒</td><td style="text-align:center;">衡量<strong>完整业务流程</strong>的处理能力（如一次下单、一次转账，包含多步接口调用）</td></tr><tr><td style="text-align:center;"><strong>QPS</strong></td><td style="text-align:center;">Query per Second</td><td style="text-align:center;">系统每秒处理查询次数，单位：次 / 秒</td><td style="text-align:center;">衡量<strong>单个接口 / 查询</strong>的处理能力，多用于接口服务、数据库查询场景</td></tr></tbody></table><h4 id="关键补充说明" tabindex="-1">关键补充说明 <a class="header-anchor" href="#关键补充说明" aria-label="Permalink to &quot;关键补充说明&quot;">​</a></h4><ul><li><p>特殊等价场景：对于互联网业务中<strong>仅包含一个请求连接的简单业务</strong>，<code>TPS = QPS = HPS</code>，三者数值一致。</p></li><li><p>选型原则：</p><ul><li>评估<strong>完整业务链路</strong>性能 → 用 <strong>TPS</strong></li><li>评估<strong>单个接口 / 查询</strong>性能 → 用 <strong>QPS</strong></li><li>评估<strong>前端页面点击 / 访问</strong>性能 → 用 <strong>HPS</strong></li></ul></li></ul><hr><h3 id="_3-不同行业-tps-参考基准-非互联网化活动场景" tabindex="-1">3. 不同行业 TPS 参考基准（非互联网化活动场景） <a class="header-anchor" href="#_3-不同行业-tps-参考基准-非互联网化活动场景" aria-label="Permalink to &quot;3. 不同行业 TPS 参考基准（非互联网化活动场景）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">行业类型</th><th style="text-align:center;">TPS 参考范围</th><th style="text-align:center;">说明</th></tr></thead><tbody><tr><td style="text-align:center;">金融行业</td><td style="text-align:center;">1000TPS ~ 50000TPS</td><td style="text-align:center;">传统金融核心交易，不包含互联网营销活动</td></tr><tr><td style="text-align:center;">保险行业</td><td style="text-align:center;">100TPS ~ 100000TPS</td><td style="text-align:center;">传统保险业务，不包含互联网化活动</td></tr><tr><td style="text-align:center;">制造行业</td><td style="text-align:center;">10TPS ~ 5000TPS</td><td style="text-align:center;">工业系统、ERP 等内部业务系统</td></tr><tr><td style="text-align:center;">互联网电子商务</td><td style="text-align:center;">10000TPS ~ 1000000TPS</td><td style="text-align:center;">电商平台、大促场景，高并发需求</td></tr><tr><td style="text-align:center;">互联网中型网站</td><td style="text-align:center;">1000TPS ~ 50000TPS</td><td style="text-align:center;">常规中流量互联网平台</td></tr><tr><td style="text-align:center;">互联网小型网站</td><td style="text-align:center;">500TPS ~ 10000TPS</td><td style="text-align:center;">低流量个人 / 小型企业网站</td></tr></tbody></table><hr><h3 id="_4-补充指标-最大响应时间-max-response-time" tabindex="-1">4. 补充指标：最大响应时间（Max Response Time） <a class="header-anchor" href="#_4-补充指标-最大响应时间-max-response-time" aria-label="Permalink to &quot;4. 补充指标：最大响应时间（Max Response Time）&quot;">​</a></h3><p><strong>定义</strong>：用户发出请求 / 指令后，系统做出响应的最大耗时。</p><p><strong>核心意义</strong>：用于排查系统性能瓶颈，监控极端场景下的用户体验，避免 “平均响应时间正常，但部分请求超时” 的问题。</p><hr><h2 id="二、指标间核心关系与优化逻辑" tabindex="-1">二、指标间核心关系与优化逻辑 <a class="header-anchor" href="#二、指标间核心关系与优化逻辑" aria-label="Permalink to &quot;二、指标间核心关系与优化逻辑&quot;">​</a></h2><h3 id="_1-核心公式" tabindex="-1">1. 核心公式 <a class="header-anchor" href="#_1-核心公式" aria-label="Permalink to &quot;1. 核心公式&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系统吞吐量（QPS/TPS） = 并发数 / 平均响应时间</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>并发数不变时，<strong>响应时间越短，吞吐量越高</strong></li><li>吞吐量不变时，<strong>响应时间越短，可承载的并发数越高</strong></li></ul><h3 id="_2-优化优先级" tabindex="-1">2. 优化优先级 <a class="header-anchor" href="#_2-优化优先级" aria-label="Permalink to &quot;2. 优化优先级&quot;">​</a></h3><ol><li><strong>先保障响应时间</strong>：优先将核心接口 RT 控制在用户可接受范围（如接口 RT &lt; 200ms）</li><li><strong>再提升吞吐量</strong>：在 RT 稳定的前提下，优化 TPS/QPS，提升系统承载能力</li><li><strong>监控极端值</strong>：同步监控最大响应时间，避免长尾请求影响整体体验</li></ol>',24)])])}const x=e(s,[["render",l]]);export{p as __pageData,x as default};
